import React from 'react';
import { SortableList } from './SortableList';
import type { ListItem } from './SortableList';

const INITIAL_ITEMS: ListItem[] = [
  { id: '1', label: 'Learn React' },
  { id: '2', label: 'Build a project' },
  { id: '3', label: 'Write tests' },
  { id: '4', label: 'Deploy to production' },
  { id: '5', label: 'Celebrate' },
];

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Priority List</h1>
      <SortableList items={INITIAL_ITEMS} />
    </div>
  );
}

import React from 'react';
import './styles.css';

export interface ListItem {
  id: string;
  label: string;
}

interface SortableListProps {
  items: ListItem[];
  onChange?: (items: ListItem[]) => void;
}

export const SortableList: React.FC<SortableListProps> = ({
  items: initialItems,
  onChange,
}) => {
  // TODO: Store items in state
  // TODO: Implement moveUp and moveDown functions

  return (
    <ul data-testid="sortable-list" className="sl">
      {initialItems.map((item, index) => (
        <li key={item.id} data-testid={`item-${index}`} className="sl__item">
          <span className="sl__rank">{index + 1}</span>
          <span className="sl__label">{item.label}</span>
          <div className="sl__actions">
            <button
              data-testid={`move-up-${index}`}
              className="sl__btn"
              aria-label={`Move ${item.label} up`}
            >
              &#9650;
            </button>
            <button
              data-testid={`move-down-${index}`}
              className="sl__btn"
              aria-label={`Move ${item.label} down`}
            >
              &#9660;
            </button>
          </div>
        </li>
      ))}
    </ul>
  );
};

export default SortableList;

.sl {
  list-style: none;
  padding: 0;
  margin: 0;
  max-width: 28rem;
  border: 1px solid #e5e7eb;
  border-radius: 0.5rem;
  overflow: hidden;
}

.sl__item {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.75rem 1rem;
  background: white;
  transition: background-color 0.15s ease;
}

.sl__item + .sl__item {
  border-top: 1px solid #f3f4f6;
}

.sl__item:hover {
  background: #f9fafb;
}

.sl__rank {
  width: 1.5rem;
  height: 1.5rem;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #eff6ff;
  color: #3b82f6;
  font-size: 0.75rem;
  font-weight: 700;
  border-radius: 9999px;
  flex-shrink: 0;
}

.sl__label {
  flex: 1;
  font-size: 0.875rem;
  color: #1f2937;
}

.sl__actions {
  display: flex;
  gap: 0.25rem;
}

.sl__btn {
  width: 1.75rem;
  height: 1.75rem;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 1px solid #d1d5db;
  border-radius: 0.25rem;
  background: white;
  cursor: pointer;
  font-size: 0.625rem;
  color: #6b7280;
  transition: all 0.1s ease;
}

.sl__btn:hover:not(:disabled) {
  background: #eff6ff;
  border-color: #93c5fd;
  color: #2563eb;
}

.sl__btn:disabled {
  opacity: 0.3;
  cursor: not-allowed;
}

