import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import { SortableList } from './SortableList';

const ITEMS = [
  { id: 'a', label: 'Alpha' },
  { id: 'b', label: 'Bravo' },
  { id: 'c', label: 'Charlie' },
];

describe('SortableList', () => {
  it('renders all items in order', () => {
    render(<SortableList items={ITEMS} />);
    expect(screen.getByTestId('item-0')).toHaveTextContent('Alpha');
    expect(screen.getByTestId('item-1')).toHaveTextContent('Bravo');
    expect(screen.getByTestId('item-2')).toHaveTextContent('Charlie');
  });

  it('disables Move Up on first item', () => {
    render(<SortableList items={ITEMS} />);
    expect(screen.getByTestId('move-up-0')).toBeDisabled();
  });

  it('disables Move Down on last item', () => {
    render(<SortableList items={ITEMS} />);
    expect(screen.getByTestId('move-down-2')).toBeDisabled();
  });

  it('moves an item up', () => {
    render(<SortableList items={ITEMS} />);
    fireEvent.click(screen.getByTestId('move-up-1'));
    expect(screen.getByTestId('item-0')).toHaveTextContent('Bravo');
    expect(screen.getByTestId('item-1')).toHaveTextContent('Alpha');
  });

  it('moves an item down', () => {
    render(<SortableList items={ITEMS} />);
    fireEvent.click(screen.getByTestId('move-down-0'));
    expect(screen.getByTestId('item-0')).toHaveTextContent('Bravo');
    expect(screen.getByTestId('item-1')).toHaveTextContent('Alpha');
  });

  it('updates disabled state after a move', () => {
    render(<SortableList items={ITEMS} />);
    fireEvent.click(screen.getByTestId('move-up-1'));
    expect(screen.getByTestId('move-up-0')).toBeDisabled();
    expect(screen.getByTestId('move-down-2')).toBeDisabled();
  });

  it('calls onChange with the reordered array', () => {
    const spy = jest.fn();
    render(<SortableList items={ITEMS} onChange={spy} />);
    fireEvent.click(screen.getByTestId('move-down-0'));
    expect(spy).toHaveBeenCalledWith([
      { id: 'b', label: 'Bravo' },
      { id: 'a', label: 'Alpha' },
      { id: 'c', label: 'Charlie' },
    ]);
  });
});

